import axios from "axios";
import React, { useState } from "react";
import Swal from 'sweetalert2';

function Category()
{
    //
    const [categoryInput, setCategory] = useState({
        slug: '',
        name: '',
        description: '',
        status: '',
        meta_title: '',
        meta_keyboard: '',
        meta_descrip: '',
        error_list: [],
    });

    //deals with setCategory
    const handleInput = (e) =>
    {
        e.persist();
        setCategory({...categoryInput, [e.target.name]: e.target.value})
    }

    //deal with submitCategory
    const submitCategory = (e) =>
    {
        e.preventDefault();

        const data = 
        {
            slug: categoryInput.slug,
            name: categoryInput.name,
            description: categoryInput.description,
            status: categoryInput.status,
            meta_title: categoryInput.meta_title,
            meta_keyboard: categoryInput.meta_keyboard,
            meta_descrip: categoryInput.meta_descrip,
        }

        //send data
        axios.post('/api/store-category', data).then(res =>
        {
            if(res.status === 200)
            {
                Swal("Success", res.data.message, "success");
                document.getElementById("CATEGORY_FORM").reset();
            }
            else if(res.status === 400)
            {
                setCategory({...categoryInput, error_list: res.data.errors});
            }
        });
    }


    return (
        <div className="container-fluid px-4">
            <h1 className="mt-4"> Add Category</h1>
            <form onSubmit= {submitCategory} id="CATEGORY_FORM">
                <ul className="nav nav-tabs" id="myTab" role="tablist">
                    <li className="nav-item" role="presentation">
                        <button className="nav-link active" id="home-tab" data-bs-toggle="tab" data-bs-target="#home-tab-pane" type="button" role="tab" aria-controls="home-tab-pane" aria-selected="true">Home</button>
                    </li>
                    <li className="nav-item" role="presentation">
                        <button className="nav-link" id="profile-tab" data-bs-toggle="tab" data-bs-target="#seo-tags" type="button" role="tab" aria-controls="seo-tags" aria-selected="false">SEO tags</button>
                    </li>
                </ul>

                <div className="tab-content" id="myTabContent">
                    <div className="tab-pane card-body border fade show active" id="home" role="tabpanel" aria-labelledby="home-tab">
                    <div className="form-group mb-3">
                        <label>Slug</label>
                        <input type="text" name="slug" onChange={handleInput} value={categoryInput.slug} className="form-control" />
                    </div>

                    <div className="form-group mb-3">
                        <label>Name</label>
                        <input type="text" name="name" onChange={handleInput} value={categoryInput.name} className="form-control" />
                    </div>

                    <div className="form-group mb-3">
                        <label>Description</label>
                        <input type="text" name="description" onChange={handleInput} value={categoryInput.description} className="form-control" />
                    </div>

                    <div className="form-group mb-3">
                        <label>Status</label>
                        <input type="checkbox" name="status" onChange={handleInput} value={categoryInput.status}/> Status 0=shown/1=hidden
                    </div>
                </div>

                <div>
                    <div className="tab-pane card-body border fade show active" id="seo-tags" role="tabpanel" aria-labelledby="seo-tags-tab">

                        <div className="form-group mb-3">
                            <label>Meta Title</label>
                            <input type="text" name="meta_title" onChange={handleInput} value={categoryInput.meta_title} className="form-control" />
                        </div>

                        <div className="form-group mb-3">
                            <label>Meta Keyboard</label>
                            <input type="text" name="meta_keyboard" onChange={handleInput} value={categoryInput.meta_keyboard} className="form-control" />
                        </div>

                         <div className="form-group mb-3">
                            <label>Meta Description</label>
                            <input type="text" name="meta_descrip" onChange={handleInput} value={categoryInput.meta_descrip} className="form-control" />
                        </div>
                            <button type= "submit" className="btn btn-primary px-4 float-end">Submit</button>
                        </div>
                    </div>
                </div>
            </form>
        </div>
);}
export default Category;
